const recipe = $json;

function sqlQuote(value) {
  if (value === null || value === undefined) return 'NULL';
  return `'${String(value).replace(/'/g, "''")}'`;
}

function jsonQuote(value) {
  return `${sqlQuote(JSON.stringify(value ?? null))}::jsonb`;
}

const videoId = recipe.source?.video_id || recipe.metadata?.video_id || '';
const videoUrl = recipe.source?.video_url || (videoId ? `https://www.youtube.com/watch?v=${videoId}` : '');

const values = {
  title: recipe.title || '',
  category: recipe.category || 'Інше',
  description: recipe.description || '',
  recipe_text: recipe,
  ingredients: recipe.ingredients || [],
  steps: recipe.steps || [],
  nutrition: recipe.nutrition || {},
  youtube_url: videoUrl,
  youtube_channel: recipe.source?.youtube_channel || '',
  thumbnail_url: recipe.source?.thumbnail_url || '',
  video_id: videoId,
  transcript: recipe.transcription?.text || '',
  transcript_language: recipe.transcription?.language || '',
  transcript_source: recipe.transcription?.source || 'description_only',
  transcription_warning: recipe.transcription?.warning || ''
};

const saveRecipeSql = `INSERT INTO recipes (
  title, category, description, recipe_text, ingredients, steps, nutrition,
  youtube_url, youtube_channel, thumbnail_url, video_id,
  transcript, transcript_language, transcript_source, transcription_warning,
  processed, created_at, updated_at
) VALUES (
  ${sqlQuote(values.title)}, ${sqlQuote(values.category)}, ${sqlQuote(values.description)},
  ${jsonQuote(values.recipe_text)}, ${jsonQuote(values.ingredients)}, ${jsonQuote(values.steps)}, ${jsonQuote(values.nutrition)},
  ${sqlQuote(values.youtube_url)}, ${sqlQuote(values.youtube_channel)}, ${sqlQuote(values.thumbnail_url)}, ${sqlQuote(values.video_id)},
  ${sqlQuote(values.transcript)}, ${sqlQuote(values.transcript_language)}, ${sqlQuote(values.transcript_source)}, ${sqlQuote(values.transcription_warning)},
  false, NOW(), NOW()
)
ON CONFLICT (video_id) DO UPDATE SET
  title = EXCLUDED.title,
  category = EXCLUDED.category,
  description = EXCLUDED.description,
  recipe_text = EXCLUDED.recipe_text,
  ingredients = EXCLUDED.ingredients,
  steps = EXCLUDED.steps,
  nutrition = EXCLUDED.nutrition,
  transcript = EXCLUDED.transcript,
  transcript_language = EXCLUDED.transcript_language,
  transcript_source = EXCLUDED.transcript_source,
  transcription_warning = EXCLUDED.transcription_warning,
  updated_at = NOW()
RETURNING id, video_id, title;`;

return [{ json: { ...recipe, save_recipe_sql: saveRecipeSql } }];
